"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[4006],{5346(e){e.exports=JSON.parse('{"tag":{"label":"persona:data-engineer","permalink":"/tags/persona-data-engineer","allTagsPath":"/tags","count":6,"items":[{"id":"catalog/development/data-handling/compress-stored-data","title":"Compress stored data","description":"Description","permalink":"/catalog/development/data-handling/compress-stored-data"},{"id":"catalog/development/pre-trained-transfer-learning","title":"Leverage pre-trained models and transfer learning for AI/ML development","description":"As part of your AI/ML process, you should evaluate using a pre-trained model and use transfer learning to avoid training a new model from scratch.","permalink":"/catalog/development/pre-trained-transfer-learning"},{"id":"catalog/operations/resource-lifecycle/optimise-storage-resource-utilisation","title":"Optimise storage utilization","description":"It\'s better to maximise storage utilisation so the storage layer is optimised for the task, not only in terms of energy proportionality but also in terms of embodied carbon. Two storage units running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilised storage unit could be more efficiently used for another task or process.","permalink":"/catalog/operations/resource-lifecycle/optimise-storage-resource-utilisation"},{"id":"catalog/architecture/compress-ml-models-for-inference","title":"Optimize the size of AI/ML models","description":"Large-scale AI/ML models require significant storage space and take more resources to run as compared to optimized models.","permalink":"/catalog/architecture/compress-ml-models-for-inference"},{"id":"catalog/operations/resource-lifecycle/set-retention-policy-on-storage-resources","title":"Set storage retention policies","description":"From an embodied carbon perspective, it\'s better to have an automated mechanism to delete unused storage resources so we are efficient with hardware and so that the storage layer is optimised for the task.","permalink":"/catalog/operations/resource-lifecycle/set-retention-policy-on-storage-resources"},{"id":"catalog/architecture/technology-selection/efficent-format-for-model-training","title":"Use efficient file formats for AI/ML development","description":"Efficient storage of the model becomes extremely important to manage the data used for ML model development.","permalink":"/catalog/architecture/technology-selection/efficent-format-for-model-training"}],"unlisted":false}}')}}]);